from quota.limiter import TokenBucket


def test_restart_elapsed_time_and_backward_clock_correction_are_both_bounded():
    old = {"mono": 3000.0, "wall": 10000.0}
    bucket = TokenBucket(5, 1, lambda: old["mono"], lambda: old["wall"])
    assert bucket.consume(4)
    payload = bucket.snapshot()

    later = {"mono": 7.0, "wall": 10003.0}
    refilled = TokenBucket.restore(payload, 5, 1, lambda: later["mono"], lambda: later["wall"])
    assert refilled.tokens == 4

    corrected = {"mono": 8.0, "wall": 9990.0}
    bounded = TokenBucket.restore(payload, 5, 1, lambda: corrected["mono"], lambda: corrected["wall"])
    assert bounded.tokens == 1
